<template>
  <view class="order-container">
    <!-- 使用 uni-app 的 tabs 组件 -->
    <view class="tabs-container">
      <view class="tab-bar">
        <view 
          class="tab-bar-item" 
          :class="{ active: activeTab === 'all' }"
          @click="changeTab('all')"
        >
          全部订单
        </view>
        <view 
          class="tab-bar-item" 
          :class="{ active: activeTab === 'unpaid' }"
          @click="changeTab('unpaid')"
        >
          待付款
        </view>
        <view 
          class="tab-bar-item" 
          :class="{ active: activeTab === 'paid' }"
          @click="changeTab('paid')"
        >
          已付款
        </view>
      </view>
      
      <view class="tab-content">
        <!-- 全部订单 -->
        <view v-if="activeTab === 'all'">
          <scroll-view scroll-y :style="{ height: scrollHeight }">
            <view 
              v-for="item in orderList.all" 
              :key="item.id" 
              class="order-item"
            >
              <view class="order-header">
                <text>订单号：{{ item.id }}</text>
                <text class="order-time">{{ item.createTime }}</text>
              </view>
              
              <view class="order-body">
                <text class="product-name">{{ item.productName }}</text>
                <text class="product-price">¥{{ item.price }}</text>
              </view>
              
              <view class="order-footer">
                <text :class="['status', item.status === 0 ? 'unpaid' : 'paid']">
                  {{ item.status === 0 ? '待付款' : '已付款' }}
                </text>
                <button 
                  v-if="item.status === 0"
                  type="primary" 
                  size="mini" 
                  @click="handlePay(item.id)"
                >
                  支付
                </button>
              </view>
            </view>
            
            <view v-if="loading" class="loading">加载中...</view>
            <view v-if="!loading && orderList.all.length === 0" class="empty">
              暂无订单
            </view>
          </scroll-view>
        </view>
        
        <!-- 待付款订单 -->
        <view v-if="activeTab === 'unpaid'">
          <scroll-view scroll-y :style="{ height: scrollHeight }">
            <view 
              v-for="item in orderList.unpaid" 
              :key="item.id" 
              class="order-item"
            >
              <view class="order-body">
                <text class="product-name">{{ item.productName }}</text>
                <text class="product-price">¥{{ item.price }}</text>
              </view>
              <view class="order-footer">
                <button 
                  type="primary" 
                  size="mini" 
                  @click="handlePay(item.id)"
                >
                  去支付
                </button>
              </view>
            </view>
            
            <view v-if="loading" class="loading">加载中...</view>
            <view v-if="!loading && orderList.unpaid.length === 0" class="empty">
              暂无待付款订单
            </view>
          </scroll-view>
        </view>
        
        <!-- 已付款订单 -->
        <view v-if="activeTab === 'paid'">
          <scroll-view scroll-y :style="{ height: scrollHeight }">
            <view 
              v-for="item in orderList.paid" 
              :key="item.id" 
              class="order-item"
            >
              <view class="order-body">
                <text class="product-name">{{ item.productName }}</text>
                <text class="product-price">¥{{ item.price }}</text>
              </view>
              <view class="order-footer">
                <text class="pay-time">{{ item.payTime }}</text>
              </view>
            </view>
            
            <view v-if="loading" class="loading">加载中...</view>
            <view v-if="!loading && orderList.paid.length === 0" class="empty">
              暂无已付款订单
            </view>
          </scroll-view>
        </view>
      </view>
    </view>
  </view>
</template>

<script>
import { ref } from 'vue'
import { get, put } from '@/utils/request'

export default {
  setup() {
    const activeTab = ref('all')
    const loading = ref(false)
    const orderList = ref({
      all: [],
      unpaid: [],
      paid: []
    })
    const scrollHeight = ref('100vh')
    
    // 生命周期
    onMounted(() => {
      loadInitialData()
      // 计算滚动区域高度
      calculateScrollHeight()
    })
    
    onShow(() => {
      refreshCurrentTab()
    })
    
    // 计算滚动区域高度
    const calculateScrollHeight = () => {
      const systemInfo = uni.getSystemInfoSync()
      const windowHeight = systemInfo.windowHeight
      // 减去 tab 栏高度（假设50px）
      scrollHeight.value = (windowHeight - 50) + 'px'
    }
    
    // 初始化加载数据
    const loadInitialData = async () => {
      try {
        loading.value = true
        await fetchAllOrders()
      } catch (error) {
        showError('初始化数据失败', error)
      } finally {
        loading.value = false
      }
    }
    
    // 刷新当前标签页
    const refreshCurrentTab = async () => {
      try {
        loading.value = true
        
        if (activeTab.value === 'all') {
          await fetchAllOrders()
        } else if (activeTab.value === 'unpaid') {
          await fetchUnpaidOrders()
        } else if (activeTab.value === 'paid') {
          await fetchPaidOrders()
        }
      } catch (error) {
        showError('刷新数据失败', error)
      } finally {
        loading.value = false
      }
    }
    
    // 切换标签页
    const changeTab = async (tabName) => {
      if (activeTab.value === tabName) return
      
      activeTab.value = tabName
      
      try {
        loading.value = true
        
        if (tabName === 'all') {
          await fetchAllOrders()
        } else if (tabName === 'unpaid') {
          await fetchUnpaidOrders()
        } else if (tabName === 'paid') {
          await fetchPaidOrders()
        }
      } catch (error) {
        showError('获取订单失败', error)
      } finally {
        loading.value = false
      }
    }
    
    // 支付订单
    const handlePay = async (orderId) => {
      try {
        loading.value = true
        
        // 1. 支付操作
        const res = await put(`/order/${orderId}/pay`, {})
        if (!res.success) throw new Error(res.message || '支付失败')
        
        // 2. 显示成功提示
        uni.showToast({ 
          title: '支付成功', 
          icon: 'success' 
        })
        
        // 3. 刷新当前标签数据
        const refreshMap = {
          all: fetchAllOrders,
          unpaid: fetchUnpaidOrders,
          paid: fetchPaidOrders
        }
        await refreshMap[activeTab.value]?.()
        
      } catch (error) {
        console.error('支付失败:', error)
        const msgMap = {
          404: '订单不存在',
          403: '无权操作此订单'
        }
        uni.showToast({ 
          title: msgMap[error.status] || '支付失败', 
          icon: 'none' 
        })
      } finally {
        loading.value = false
      }
    }
    
    // ---------- 网络请求方法 ----------
    const fetchAllOrders = async () => {
      const res = await get('/order/all')
      orderList.value.all = res.data || []
    }
    
    const fetchUnpaidOrders = async () => {
      const res = await get('/order/status/0')
      orderList.value.unpaid = res.data || []
    }
    
    const fetchPaidOrders = async () => {
      const res = await get('/order/status/1')
      orderList.value.paid = res.data || []
    }
    
    // ---------- 工具方法 ----------
    const showError = (defaultMsg, error) => {
      console.error(error)
      uni.showToast({
        title: error?.message || defaultMsg,
        icon: 'none'
      })
    }
    
    return {
      activeTab,
      loading,
      orderList,
      scrollHeight,
      changeTab,
      handlePay
    }
  }
}
</script>

